local SumRecharges = MemoryPool.newTable()

SumRechargeConfig = {}

local function initSumRecharges(config)
    for _, item in pairs(config) do
        table.insert(SumRecharges, {
            Id = item.Id,
            Sex = tonumber(item.Sex),
            MainUIName = item.MainUIName,
            LayoutUIName = item.LayoutUIName,
            ResultUIName = item.ResultUIName,
            RewardUIName = item.RewardUIName,
            MainIcon = item.MainIcon,
            MainIconEffect = item.MainIconEffect,
            LayoutMainImage = item.LayoutMainImage,
            LayoutSubImage = item.LayoutSubImage,
            TitleLang = item.TitleLang,
            HintLang = item.HintLang,
            ReceiveImage = item.ReceiveImage,
            RechargeImage = item.RechargeImage,
            GCube = tonumber(item.Gcube),
            Rewards = {}
        })
    end
end

local function getSumRecharge(id)
    for _, config in pairs(SumRecharges) do
        if config.Id == id then
            return config
        end
    end
end

local function initSumRechargeRewards(rewards)
    for _, reward in pairs(rewards) do
        local config = getSumRecharge(reward.SumRechargeId)
        if config then
            table.insert(config.Rewards, {
                Icon = reward.Icon,
                Effect = reward.Effect,
                Count = reward.Count,
                NameLang = reward.NameLang,
                SortWeight = tonumber(reward.SortWeight),
                DescLang = reward.DescLang or "",
                Background = reward.Background or "",
                RewardId = tonumber(reward.RewardId) or 0,
                Meta = tonumber(reward.Meta) or 0,
                OffsetX = tonumber(reward.OffsetX) or 0,
                OffsetY = tonumber(reward.OffsetY) or 0
            })
        end
    end
    for _, config in pairs(SumRecharges) do
        table.sort(config.Rewards, function(a, b)
            return a.SortWeight > b.SortWeight
        end)
    end
end

local function initSumRechargeUI()
    local player = PlayerManager:getClientPlayer()
    local sex = player:getSex()
    local config = SumRechargeConfig:getMinGCubeConfig(sex)
    if not config then
        return
    end
    ---改变是否需要记录充值的配置
    ClientHelper.putIntPrefs("EnableSumRecharge", 1)

    local UISumRechargeMain = require "base.ui.layout.GUISumRechargeMain"

    GUISumRechargeMain = UISumRechargeMain.new(config.MainUIName, GUIManager:getMainControl())
    GUISumRechargeMain:registerEvents()
    GUISumRechargeMain:onShow(config.Id)

    local UISumRechargeLayout = require "base.ui.layout.GUISumRechargeLayout"
    GUISumRechargeLayout = UISumRechargeLayout.new(config.LayoutUIName)
    GUISumRechargeLayout:registerEvents()
    GUISumRechargeLayout:onShow(config.Id)

    local UISumRechargeResult = require "base.ui.layout.GUISumRechargeResult"
    GUISumRechargeResult = UISumRechargeResult.new(config.ResultUIName)
    GUISumRechargeResult:registerEvents()
    GUISumRechargeResult:onShow(config.Id)

end

function SumRechargeConfig:init()
    local path = FileUtil:getMapPath() .. "common/SumRecharge.csv"
    local file = io.open(path, "r")
    if not file then
        return
    end
    io.close(file)
    initSumRecharges(CsvUtil.loadCsvFile(path, 2))
    path = FileUtil:getMapPath() .. "common/SumRechargeReward.csv"
    file = io.open(path, "r")
    if not file then
        return
    end
    io.close(file)
    initSumRechargeRewards(CsvUtil.loadCsvFile(path, 2))
    initSumRechargeUI()
end

function SumRechargeConfig:getSumRecharge(id)
    return getSumRecharge(id)
end

function SumRechargeConfig:getMinGCubeConfig(sex)
    local result
    for _, config in pairs(SumRecharges) do
        if config.Sex == sex or config.Sex == 0 then
            if result == nil then
                result = config
            end
            if result.GCube > config.GCube then
                result = config
            end
        end
    end
    return result
end

function SumRechargeConfig:getRechargeReward(id)
    for _, config in pairs(SumRecharges) do
        for _, reward in pairs(config.Rewards) do
            if reward.RewardId == tonumber(id) then
                return reward
            end
        end
    end
end